using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // BREAKING CHANGE 1 – Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents have {"Discriminator":"Blog",...}. Preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 – id format changed from "Blog|1" to just "1".
            // Existing documents use the "Discriminator|Key" format. Opt back in.
            entity.HasId(b => new { Discriminator = "Blog", Id = b.Id });

            // BREAKING CHANGE 3 – HasIndex() is no longer supported for Cosmos provider.
            // REMOVED: entity.HasIndex(b => b.Name);
            // Cosmos uses indexing policies at the container level, not EF indexes.
        });
    }
}

